function readCachedExchangeRate() {
try {
const cached = JSON.parse(localStorage.getItem(CURRENCY_RATE_CACHE_KEY) || "null");
const rate = Number(cached?.rate);
if (!Number.isFinite(rate) || rate <= 0)
return null;
return cached;
}
catch (error) {
return null;
}
}
function applyExchangeRate(rate, metadata = {}) {
const numericRate = Number(rate);
if (!Number.isFinite(numericRate) || numericRate <= 0)
return false;
CURRENCY_CONFIG.MYR.rate = numericRate;
CURRENCY_CONFIG.MYR.sourceName = metadata.sourceName || "Kurs otomatis";
CURRENCY_CONFIG.MYR.sourceUrl = metadata.sourceUrl || "";
CURRENCY_CONFIG.MYR.rateDate = metadata.rateDate || "";
renderCurrencyDependentUI();
return true;
}
function saveExchangeRateCache(rate, endpoint, rateDate) {
try {
localStorage.setItem(CURRENCY_RATE_CACHE_KEY, JSON.stringify({
rate,
sourceName: endpoint.name,
sourceUrl: endpoint.sourceUrl,
rateDate: rateDate || new Date().toISOString(),
fetchedAt: Date.now()
}));
}
catch (error) {
console.warn("Cache kurs tidak dapat disimpan:", error);
}
}
async function fetchJsonWithTimeout(url, timeoutMs = CURRENCY_RATE_REQUEST_TIMEOUT) {
const controller = new AbortController();
const timeoutId = setTimeout(() => controller.abort(), timeoutMs);
try {
const response = await fetch(url, {
method: "GET",
headers: { "Accept": "application/json" },
cache: "no-store",
signal: controller.signal
});
if (!response.ok) {
throw new Error(`HTTP ${response.status}`);
}
return await response.json();
}
finally {
clearTimeout(timeoutId);
}
}
async function refreshExchangeRate() {
const cached = readCachedExchangeRate();
if (cached) {
applyExchangeRate(cached.rate, {
sourceName: `${cached.sourceName || "Cache kurs"} (cache)`,
sourceUrl: cached.sourceUrl || "",
rateDate: cached.rateDate || ""
});
const cacheAge = Date.now() - Number(cached.fetchedAt || 0);
if (cacheAge >= 0 && cacheAge < CURRENCY_RATE_CACHE_TTL) {
return;
}
}
for (const endpoint of CURRENCY_RATE_ENDPOINTS) {
try {
const data = await fetchJsonWithTimeout(endpoint.url);
const rate = Number(endpoint.getRate(data));
const rateDate = endpoint.getDate(data) || new Date().toISOString();
if (!Number.isFinite(rate) || rate <= 0) {
throw new Error("Nilai kurs tidak valid");
}
saveExchangeRateCache(rate, endpoint, rateDate);
applyExchangeRate(rate, {
sourceName: endpoint.name,
sourceUrl: endpoint.sourceUrl,
rateDate
});
return;
}
catch (error) {
console.warn(`Gagal mengambil kurs dari ${endpoint.name}:`, error);
}
}
updateCurrencyRateStatus();
console.warn("Semua sumber kurs gagal. Website memakai kurs cache atau kurs cadangan.");
}
