function enableGameTabsDrag() {
const scroller = document.querySelector('.game-tabs-scroll');
if (!scroller)
return;
let activePointerId = null;
let startX = 0;
let startY = 0;
let startScrollLeft = 0;
let isDragging = false;
let suppressNextClick = false;
scroller.addEventListener('pointerdown', (event) => {
if (event.pointerType !== 'mouse' || event.button !== 0)
return;
activePointerId = event.pointerId;
startX = event.clientX;
startY = event.clientY;
startScrollLeft = scroller.scrollLeft;
isDragging = false;
});
scroller.addEventListener('pointermove', (event) => {
if (event.pointerId !== activePointerId)
return;
const deltaX = event.clientX - startX;
const deltaY = event.clientY - startY;
if (!isDragging) {
if (Math.abs(deltaX) < 6 && Math.abs(deltaY) < 6)
return;
if (Math.abs(deltaY) > Math.abs(deltaX)) {
activePointerId = null;
return;
}
isDragging = true;
scroller.classList.add('dragging');
try {
scroller.setPointerCapture(event.pointerId);
}
catch (_) { }
}
scroller.scrollLeft = startScrollLeft - deltaX;
event.preventDefault();
});
const finishDrag = (event) => {
if (event.pointerId !== activePointerId)
return;
if (isDragging) {
suppressNextClick = true;
window.setTimeout(() => {
suppressNextClick = false;
}, 120);
}
scroller.classList.remove('dragging');
try {
if (scroller.hasPointerCapture(event.pointerId)) {
scroller.releasePointerCapture(event.pointerId);
}
}
catch (_) { }
activePointerId = null;
isDragging = false;
};
scroller.addEventListener('pointerup', finishDrag);
scroller.addEventListener('pointercancel', finishDrag);
scroller.addEventListener('click', (event) => {
if (!suppressNextClick)
return;
event.preventDefault();
event.stopPropagation();
}, true);
}
function setupGameTabsNavigation() {
const scroller = document.querySelector('.game-tabs-scroll');
const previousButton = document.getElementById('game-tabs-prev');
const nextButton = document.getElementById('game-tabs-next');
if (!scroller || !previousButton || !nextButton)
return;
let updateFrame = null;
const updateArrows = () => {
const maxScrollLeft = Math.max(0, scroller.scrollWidth - scroller.clientWidth);
const hasOverflow = maxScrollLeft > 4;
const isAtStart = scroller.scrollLeft <= 4;
const isAtEnd = scroller.scrollLeft >= maxScrollLeft - 4;
previousButton.classList.toggle('is-visible', hasOverflow && !isAtStart);
nextButton.classList.toggle('is-visible', hasOverflow && !isAtEnd);
};
const requestArrowUpdate = () => {
if (updateFrame)
cancelAnimationFrame(updateFrame);
updateFrame = requestAnimationFrame(updateArrows);
};
const getScrollDistance = () => Math.max(170, Math.round(scroller.clientWidth * 0.72));
previousButton.addEventListener('click', () => {
scroller.scrollBy({ left: -getScrollDistance(), behavior: 'smooth' });
});
nextButton.addEventListener('click', () => {
scroller.scrollBy({ left: getScrollDistance(), behavior: 'smooth' });
});
scroller.addEventListener('scroll', requestArrowUpdate, { passive: true });
window.addEventListener('resize', requestArrowUpdate, { passive: true });
if ('ResizeObserver' in window) {
const resizeObserver = new ResizeObserver(requestArrowUpdate);
resizeObserver.observe(scroller);
const track = scroller.querySelector('.game-tabs-track');
if (track)
resizeObserver.observe(track);
}
requestArrowUpdate();
}
