function readCachedProducts() {
try {
const cached = JSON.parse(sessionStorage.getItem(PRODUCTS_CACHE_KEY) || "null");
if (!cached || !Array.isArray(cached.data))
return null;
if (Date.now() - cached.savedAt > PRODUCTS_CACHE_TTL)
return null;
return cached.data.map(normalizeProductRecord);
}
catch (_) {
return null;
}
}
