function calculateReviewSummary(comments) {
const ratings = (Array.isArray(comments) ? comments : [])
.map(comment => Number(comment.Rating || 0))
.filter(rating => rating >= 1 && rating <= 5);
return {
total: ratings.length,
average: ratings.length
? ratings.reduce((sum, rating) => sum + rating, 0) / ratings.length
: 0
};
}
function renderGameRatingSummary(gameName, reviewSummary, state = "ready") {
if (currentGameFilter !== gameName)
return;
const desktopAverage = document.getElementById("sidebar-game-rating-average");
const desktopStars = document.getElementById("sidebar-game-rating-stars");
const desktopMeta = document.getElementById("sidebar-game-rating-meta");
const mobileAverage = document.getElementById("mobile-game-rating-average");
const mobileStars = document.getElementById("mobile-game-rating-stars");
const mobileMeta = document.getElementById("mobile-game-rating-meta");
const averageElements = [desktopAverage, mobileAverage].filter(Boolean);
const starsElements = [desktopStars, mobileStars].filter(Boolean);
const metaElements = [desktopMeta, mobileMeta].filter(Boolean);
if (!averageElements.length && !starsElements.length && !metaElements.length)
return;
const setAverage = value => averageElements.forEach(element => {
element.textContent = value;
});
const setStars = html => starsElements.forEach(element => {
element.innerHTML = html;
});
const setMeta = value => metaElements.forEach(element => {
element.textContent = value;
});
if (state === "loading") {
setAverage("—");
setStars('<i class="fa-solid fa-spinner fa-spin text-slate-400" aria-hidden="true"></i>');
setMeta("Mengambil rating dari ulasan game...");
return;
}
if (state === "error") {
setAverage("—");
setStars(createStarsHTML(0));
setMeta("Rating belum dapat dimuat");
return;
}
const total = Number(reviewSummary?.total || 0);
const average = Number(reviewSummary?.average || 0);
setAverage(total ? average.toFixed(1) : "0.0");
setStars(createStarsHTML(average));
setMeta(total
? `${total.toLocaleString("id-ID")} ulasan ${gameName}`
: `Belum ada ulasan untuk ${gameName}`);
}
async function getGameReviewSummaryData(gameName) {
if (!gameName || gameName === "Semua") {
return { average: 0, total: 0 };
}
if (gameReviewSummaryCache.has(gameName)) {
return gameReviewSummaryCache.get(gameName);
}
if (gameReviewSummaryPromiseCache.has(gameName)) {
return gameReviewSummaryPromiseCache.get(gameName);
}
const requestPromise = (async () => {
const representativeProduct = getReadyProductsByGame(gameName)[0];
const productId = String(representativeProduct?.ID || "");
if (!productId) {
const emptySummary = { average: 0, total: 0, comments: [] };
gameReviewSummaryCache.set(gameName, emptySummary);
return emptySummary;
}
let comments;
if (reviewCache.has(productId)) {
comments = reviewCache.get(productId);
}
else {
const url = new URL(API_URL);
url.searchParams.set("action", "comments");
url.searchParams.set("id_produk", productId);
url.searchParams.set("_", Date.now().toString());
const response = await fetch(url.toString(), { cache: "no-store" });
if (!response.ok)
throw new Error(`HTTP ${response.status}`);
const result = await response.json();
if (!result.success) {
throw new Error(result.message || "API menolak permintaan ulasan.");
}
comments = Array.isArray(result.comments) ? result.comments : [];
reviewCache.set(productId, comments);
}
const summary = {
...calculateReviewSummary(comments),
comments: comments.map(comment => ({
...comment,
__gameName: gameName
}))
};
gameReviewSummaryCache.set(gameName, summary);
return summary;
})();
gameReviewSummaryPromiseCache.set(gameName, requestPromise);
try {
return await requestPromise;
}
finally {
gameReviewSummaryPromiseCache.delete(gameName);
}
}
async function loadGameReviewSummary(gameName) {
if (!gameName || gameName === "Semua")
return;
renderGameRatingSummary(gameName, null, "loading");
const requestId = ++gameReviewSummaryRequestId;
try {
const summary = await getGameReviewSummaryData(gameName);
if (requestId === gameReviewSummaryRequestId) {
renderGameRatingSummary(gameName, summary);
}
}
catch (error) {
console.error("Gagal mengambil ringkasan rating game:", error);
if (requestId === gameReviewSummaryRequestId) {
renderGameRatingSummary(gameName, null, "error");
}
}
}
function renderAllGameRatingCardState(gameName, summary, state = "ready") {
const card = [...document.querySelectorAll("[data-all-game-rating]")]
.find(element => element.dataset.allGameRating === gameName);
if (!card)
return;
const score = card.querySelector("[data-rating-score]");
const stars = card.querySelector("[data-rating-stars]");
const meta = card.querySelector("[data-rating-meta]");
if (state === "loading") {
if (score)
score.textContent = "—";
if (stars)
stars.innerHTML = '<i class="fa-solid fa-spinner fa-spin" aria-hidden="true"></i>';
if (meta)
meta.textContent = "Mengambil rating...";
return;
}
if (state === "error") {
if (score)
score.textContent = "—";
if (stars)
stars.innerHTML = createStarsHTML(0);
if (meta)
meta.textContent = "Rating belum dapat dimuat";
return;
}
const total = Number(summary?.total || 0);
const average = Number(summary?.average || 0);
if (score)
score.textContent = total ? average.toFixed(1) : "0.0";
if (stars)
stars.innerHTML = createStarsHTML(average);
if (meta) {
meta.textContent = total
? `${total.toLocaleString("id-ID")} ulasan`
: "Belum ada ulasan";
}
}
