function getWillpediaHistoryState() {
const state = window.history.state;
return state && typeof state === "object" ? state : {};
}
function replaceMenuHistoryState() {
if (isRestoringBrowserHistory)
return;
const currentState = getWillpediaHistoryState();
window.history.replaceState({
...currentState,
[WILLPEDIA_HISTORY_VIEW_KEY]: "menu",
gameName: "",
productId: ""
}, document.title, window.location.href);
}
function pushGameHistoryState(gameName, productId = "") {
if (isRestoringBrowserHistory || !gameName)
return;
const currentState = getWillpediaHistoryState();
const normalizedProductId = String(productId || "");
if (currentState[WILLPEDIA_HISTORY_VIEW_KEY] === "game" &&
currentState.gameName === gameName &&
String(currentState.productId || "") === normalizedProductId) {
return;
}
window.history.pushState({
[WILLPEDIA_HISTORY_VIEW_KEY]: "game",
gameName,
productId: normalizedProductId
}, document.title, window.location.href);
}
function scrollToHistoryProduct(productId) {
const normalizedProductId = String(productId || "");
if (!normalizedProductId) {
document.getElementById("game-detail-view")?.scrollIntoView({
behavior: "auto",
block: "start"
});
return;
}
window.requestAnimationFrame(() => {
window.setTimeout(() => {
const targetCard = [...document.querySelectorAll("#product-container .product-card[data-product-id]")]
.find(card => card.dataset.productId === normalizedProductId);
if (!targetCard) {
document.getElementById("game-detail-view")?.scrollIntoView({
behavior: "auto",
block: "start"
});
return;
}
targetCard.classList.add("show", "popular-target-highlight");
targetCard.scrollIntoView({
behavior: "auto",
block: "center"
});
window.setTimeout(() => {
targetCard.classList.remove("popular-target-highlight");
}, 1900);
}, 80);
});
}
function restoreWillpediaHistoryState(state) {
const targetState = state && typeof state === "object" ? state : {};
isRestoringBrowserHistory = true;
try {
if (targetState[WILLPEDIA_HISTORY_VIEW_KEY] === "game" &&
targetState.gameName) {
resetSearchDisplay();
currentGameFilter = String(targetState.gameName);
currentSubCategoryFilter = "Semua";
hideGameReviewSection();
renderCurrentProductView({ rebuildSubCategories: true });
scrollToHistoryProduct(targetState.productId || "");
return;
}
currentGameFilter = "Semua";
currentSubCategoryFilter = "Semua";
resetSearchDisplay();
const subCategoryContainer = document.getElementById("sub-category-container");
if (subCategoryContainer)
subCategoryContainer.innerHTML = "";
setCategoryFilterVisible(false);
showMenuView();
renderGameMenu();
window.requestAnimationFrame(() => {
document.getElementById("game-menu-view")?.scrollIntoView({
behavior: "auto",
block: "start"
});
});
}
finally {
isRestoringBrowserHistory = false;
}
}
function setupBrowserHistoryNavigation() {
const initialState = getWillpediaHistoryState();
if (!initialState[WILLPEDIA_HISTORY_VIEW_KEY]) {
window.history.replaceState({
...initialState,
[WILLPEDIA_HISTORY_VIEW_KEY]: "menu",
gameName: "",
productId: ""
}, document.title, window.location.href);
}
else if (initialState[WILLPEDIA_HISTORY_VIEW_KEY] === "game" &&
initialState.gameName) {
currentGameFilter = String(initialState.gameName);
currentSubCategoryFilter = "Semua";
}
window.addEventListener("popstate", event => {
restoreWillpediaHistoryState(event.state);
});
}
function showGameMenuFromButton() {
const historyState = getWillpediaHistoryState();
if (!isRestoringBrowserHistory &&
historyState[WILLPEDIA_HISTORY_VIEW_KEY] === "game") {
window.history.back();
return;
}
currentGameFilter = "Semua";
currentSubCategoryFilter = "Semua";
resetSearchDisplay();
const subCategoryContainer = document.getElementById("sub-category-container");
if (subCategoryContainer)
subCategoryContainer.innerHTML = "";
setCategoryFilterVisible(false);
showMenuView();
renderGameMenu();
replaceMenuHistoryState();
document.getElementById("game-menu-view")?.scrollIntoView({
behavior: "smooth",
block: "start"
});
}
function openGamePricelist(gameName) {
const normalizedGameName = String(gameName || "").trim();
if (!normalizedGameName)
return;
pushGameHistoryState(normalizedGameName);
filterGame(normalizedGameName, null);
document.getElementById("game-detail-view")?.scrollIntoView({
behavior: "smooth",
block: "start"
});
}
