function renderMobileSearchItems(rawQuery = "") {
const container = document.getElementById("mobile-popular-games");
const title = document.getElementById("mobile-search-list-title");
if (!container)
return;
const query = String(rawQuery || "").trim();
const normalizedQuery = normalizeSearchText(query);
const readyProducts = allProducts.filter(product => product.ID && product.Status === "Ready");
if (normalizedQuery) {
if (title)
title.textContent = "Hasil Pencarian";
const matches = readyProducts
.filter(product => getMobileSearchableText(product).includes(normalizedQuery))
.slice(0, 10);
if (!matches.length) {
container.innerHTML = `
                        <div class="mobile-search-empty">
                            Paket untuk “${escapeHTML(query)}” belum ditemukan.<br>
                            Tekan Enter untuk mencoba pencarian lengkap.
                        </div>
                    `;
return;
}
container.innerHTML = matches.map(product => {
const imageInfo = getProductImageInfo(product);
const imageUrl = escapeHTML(imageInfo.primaryUrl || PRODUCT_IMAGE_FALLBACK);
const originalUrl = escapeHTML(imageInfo.originalUrl || "");
const packageName = String(product.Nama_Paket || product.Nama || "Paket Joki");
const encodedPackage = encodeURIComponent(packageName);
const meta = [product.Game, product.Kategori].filter(Boolean).join(" • ");
return `
                        <button type="button" class="mobile-popular-item" onclick="selectPackageFromMobileSearch('${encodedPackage}')">
                            <img
                                src="${imageUrl}"
                                data-original-src="${originalUrl}"
                                alt="${escapeHTML(packageName)}"
                                class="mobile-popular-image"
                                loading="lazy"
                                decoding="async"
                                referrerpolicy="no-referrer"
                                onerror="handleProductImageError(this)"
                            >
                            <span class="mobile-popular-info">
                                <span class="mobile-popular-name">${escapeHTML(packageName)}</span>
                                <span class="mobile-popular-meta">${escapeHTML(meta || "Paket joki")}</span>
                            </span>
                            <i class="fa-solid fa-chevron-right mobile-popular-chevron" aria-hidden="true"></i>
                        </button>
                    `;
}).join("");
return;
}
if (title)
title.textContent = "Populer";
const availableGames = GAME_MENU_ORDER.filter(gameName => readyProducts.some(product => product.Game === gameName));
if (!availableGames.length) {
container.innerHTML = `
                    <div class="mobile-search-empty">
                        Pilihan game sedang dimuat. Silakan tunggu sebentar.
                    </div>
                `;
return;
}
container.innerHTML = availableGames.map(gameName => {
const products = readyProducts.filter(product => product.Game === gameName);
const imageInfo = getGameMenuImageInfo(gameName, products);
const imageUrl = escapeHTML(imageInfo.primaryUrl || PRODUCT_IMAGE_FALLBACK);
const originalUrl = escapeHTML(imageInfo.originalUrl || "");
const encodedGame = encodeURIComponent(gameName);
return `
                    <button type="button" class="mobile-popular-item" onclick="selectGameFromMobileSearch('${encodedGame}')">
                        <img
                            src="${imageUrl}"
                            data-original-src="${originalUrl}"
                            alt="${escapeHTML(gameName)}"
                            class="mobile-popular-image"
                            loading="lazy"
                            decoding="async"
                            referrerpolicy="no-referrer"
                            onerror="handleProductImageError(this)"
                        >
                        <span class="mobile-popular-info">
                            <span class="mobile-popular-name">${escapeHTML(gameName)}</span>
                            <span class="mobile-popular-meta">${products.length} paket joki tersedia</span>
                        </span>
                        <i class="fa-solid fa-chevron-right mobile-popular-chevron" aria-hidden="true"></i>
                    </button>
                `;
}).join("");
}
function selectGameFromMobileSearch(encodedGameName) {
const gameName = decodeURIComponent(encodedGameName);
closeMobileSearch();
openGamePricelist(gameName);
}
function selectPackageFromMobileSearch(encodedPackageName) {
const packageName = decodeURIComponent(encodedPackageName);
const desktopInput = document.getElementById("joki-search-input");
if (desktopInput)
desktopInput.value = packageName;
closeMobileSearch();
performJokiSearch(packageName);
}
function goToMobileGameMenu() {
setMobileMenuState(false);
showGameMenuFromButton();
}
function openMobileOrderFromMenu() {
setMobileMenuState(false);
if (!cart.length) {
showToast("Pilih paket joki terlebih dahulu.");
return;
}
if (window.innerWidth < 1024 && typeof toggleMobileOrderSheet === "function") {
toggleMobileOrderSheet(true);
return;
}
openCartModal();
}
function setupMobileNavbarSearch() {
const form = document.getElementById("mobile-search-form");
const input = document.getElementById("mobile-search-input");
const clearButton = document.getElementById("mobile-search-clear");
if (!form || !input || !clearButton)
return;
form.addEventListener("submit", event => {
event.preventDefault();
const query = input.value.trim();
if (!query)
return;
const desktopInput = document.getElementById("joki-search-input");
if (desktopInput)
desktopInput.value = query;
closeMobileSearch();
performJokiSearch(query);
});
input.addEventListener("input", () => {
const query = input.value.trim();
clearButton.classList.toggle("hidden", query === "");
renderMobileSearchItems(query);
});
clearButton.addEventListener("click", () => {
input.value = "";
clearButton.classList.add("hidden");
renderMobileSearchItems("");
input.focus();
});
document.addEventListener("keydown", event => {
if (event.key !== "Escape")
return;
closeMobileSearch();
setMobileMenuState(false);
});
document.addEventListener("click", event => {
const menu = document.getElementById("mobile-nav-menu");
const menuButton = document.getElementById("mobile-menu-button");
if (!menu || menu.classList.contains("hidden"))
return;
if (menu.contains(event.target) || menuButton?.contains(event.target))
return;
setMobileMenuState(false);
});
}
function setupHeroImageCarousel() {
const root = document.getElementById('main-hero-banner');
if (!root || root.dataset.carouselReady === 'true')
return;
root.dataset.carouselReady = 'true';
const slides = Array.from(root.querySelectorAll('[data-hero-slide]'));
const dots = Array.from(root.querySelectorAll('[data-hero-dot]'));
const previousButton = root.querySelector('[data-hero-prev]');
const nextButton = root.querySelector('[data-hero-next]');
const progress = root.querySelector('[data-hero-progress]');
if (slides.length < 2)
return;
let activeIndex = 0;
let autoplayId = null;
const duration = 5500;
function restartProgress() {
if (!progress)
return;
progress.classList.remove('is-running');
void progress.offsetWidth;
progress.classList.add('is-running');
}
function showSlide(index) {
activeIndex = (index + slides.length) % slides.length;
slides.forEach((slide, slideIndex) => {
slide.classList.toggle('is-active', slideIndex === activeIndex);
});
dots.forEach((dot, dotIndex) => {
dot.classList.toggle('is-active', dotIndex === activeIndex);
dot.setAttribute('aria-current', dotIndex === activeIndex ? 'true' : 'false');
});
restartProgress();
}
function stopAutoplay() {
if (!autoplayId)
return;
window.clearInterval(autoplayId);
autoplayId = null;
}
function startAutoplay() {
stopAutoplay();
autoplayId = window.setInterval(() => showSlide(activeIndex + 1), duration);
}
previousButton?.addEventListener('click', () => {
showSlide(activeIndex - 1);
startAutoplay();
});
nextButton?.addEventListener('click', () => {
showSlide(activeIndex + 1);
startAutoplay();
});
dots.forEach((dot, index) => {
dot.addEventListener('click', () => {
showSlide(index);
startAutoplay();
});
});
let touchStartX = 0;
root.addEventListener('touchstart', event => {
touchStartX = event.changedTouches[0]?.clientX || 0;
}, { passive: true });
root.addEventListener('touchend', event => {
const touchEndX = event.changedTouches[0]?.clientX || 0;
const delta = touchStartX - touchEndX;
if (Math.abs(delta) < 40)
return;
showSlide(delta > 0 ? activeIndex + 1 : activeIndex - 1);
startAutoplay();
}, { passive: true });
root.addEventListener('mouseenter', stopAutoplay);
root.addEventListener('mouseleave', startAutoplay);
document.addEventListener('visibilitychange', () => {
if (document.hidden)
stopAutoplay();
else
startAutoplay();
});
showSlide(0);
startAutoplay();
}
window.addEventListener('DOMContentLoaded', () => {
updateNavbarState();
enableGameTabsDrag();
setupGameTabsNavigation();
setupJokiSearch();
setupMobileNavbarSearch();
setupCurrencySelector();
setupCategoryFilterDrag();
setupReviewFeature();
setupInlineReviewSection();
setupHeroImageCarousel();
setupBrowserHistoryNavigation();
loadData();
});
